const path = require("path");
const fs = require("fs");

const problemsFilePath = path.resolve(__dirname, "../../data/problems.json");

function readProblemsData() {
	const data = fs.readFileSync(problemsFilePath, "utf8");
	return JSON.parse(data);
}

/**
 * Get detailed problem info by problemId including component statistics.
 * Returns null if problem not found.
 * @param {string} problemId
 * @returns {object|null}
 */
function getProblemDetail(problemId) {
	const problemsData = readProblemsData();
	const problem = problemsData.find(p => p.id === problemId);
	if (!problem) {
		return null;
	}

	// Aggregate component statistics
	const components = problem.components || [];

	const languageCounts = {};
	const statusCounts = {};
	let maxPoints = 0;

	components.forEach(component => {
		// Count languages
		if (component.language) {
			languageCounts[component.language] = (languageCounts[component.language] || 0) + 1;
		}

		// Count statuses
		if (component.status) {
			statusCounts[component.status] = (statusCounts[component.status] || 0) + 1;
		}

		// Track max points
		if (typeof component.points === "number" && component.points > maxPoints) {
			maxPoints = component.points;
		}
	});

	return {
		id: problem.id,
		title: problem.title,
		description: problem.description,
		components: components,
		componentStats: {
			languageCounts: languageCounts,
			statusCounts: statusCounts,
			maxPoints: maxPoints
		}
	};
}

module.exports = {
	getProblemDetail
};
